import { contextBridge, ipcRenderer } from 'electron';
import { Channels } from '../shared/channels';
import type { AppConfig, OverlaySettings } from '../shared/types';

const editModalAPI = {
  close: (): void => {
    ipcRenderer.send(Channels.EDIT_MODAL_CLOSE);
  },
  save: (data: OverlaySettings): void => {
    ipcRenderer.send(Channels.EDIT_MODAL_SAVE, data);
  },
  previewOverlay: (data: OverlaySettings): void => {
    ipcRenderer.send(Channels.OVERLAY_PREVIEW, data);
  },
  testCta: (): void => {
    ipcRenderer.send(Channels.CTA_TEST);
  },
  getConfig: (): Promise<AppConfig> => ipcRenderer.invoke(Channels.CONFIG_GET),
};

contextBridge.exposeInMainWorld('editModalAPI', editModalAPI);
